const stats = $input.first().json;
const today = $now.setZone('Europe/Istanbul').toFormat('d MMMM yyyy', { locale: 'tr' });

const sourceNames = {
  business_insider: 'Business Insider Africa',
  cnbc_africa: 'CNBC Africa',
  africa_report: 'The Africa Report',
  aa_africa: 'Anadolu Ajansi Africa',
  conversation_africa: 'The Conversation Africa',
};

const rows = Array.isArray(stats) ? stats : [];

let totalScraped = 0;
let totalDup = 0;
let totalScore = 0;
let totalTr = 0;
let totalPublished = 0;

let tableRows = '';
for (const row of rows) {
  const name = sourceNames[row.source] || row.source;
  totalScraped += row.total_scraped || 0;
  totalDup += row.dropped_duplicate || 0;
  totalScore += row.dropped_low_score || 0;
  totalTr += row.dropped_turkey_filter || 0;
  totalPublished += row.published || 0;
  const avgScore = row.avg_score != null ? row.avg_score : '-';
  tableRows += `<tr>
    <td style="padding:8px 12px;border-bottom:1px solid #eee;">${name}</td>
    <td style="padding:8px 12px;border-bottom:1px solid #eee;text-align:center;">${row.total_scraped || 0}</td>
    <td style="padding:8px 12px;border-bottom:1px solid #eee;text-align:center;color:#888;">${row.dropped_duplicate || 0}</td>
    <td style="padding:8px 12px;border-bottom:1px solid #eee;text-align:center;color:#e67e22;">${row.dropped_low_score || 0}</td>
    <td style="padding:8px 12px;border-bottom:1px solid #eee;text-align:center;color:#c0392b;">${row.dropped_turkey_filter || 0}</td>
    <td style="padding:8px 12px;border-bottom:1px solid #eee;text-align:center;font-weight:bold;color:#27ae60;">${row.published || 0}</td>
    <td style="padding:8px 12px;border-bottom:1px solid #eee;text-align:center;">${avgScore}</td>
  </tr>`;
}

tableRows += `<tr style="background:#f0f4f8;">
  <td style="padding:8px 12px;font-weight:bold;">TOPLAM</td>
  <td style="padding:8px 12px;text-align:center;font-weight:bold;">${totalScraped}</td>
  <td style="padding:8px 12px;text-align:center;font-weight:bold;color:#888;">${totalDup}</td>
  <td style="padding:8px 12px;text-align:center;font-weight:bold;color:#e67e22;">${totalScore}</td>
  <td style="padding:8px 12px;text-align:center;font-weight:bold;color:#c0392b;">${totalTr}</td>
  <td style="padding:8px 12px;text-align:center;font-weight:bold;color:#27ae60;">${totalPublished}</td>
  <td style="padding:8px 12px;text-align:center;">-</td>
</tr>`;

const noDataMsg = rows.length === 0
  ? '<p style="color:#c0392b;">Bugun pipeline verisi bulunamadi. Pipeline calismamiş olabilir.</p>'
  : '';

const html = `<!DOCTYPE html>
<html><head><meta charset="utf-8"></head>
<body style="font-family:Arial,sans-serif;max-width:720px;margin:0 auto;color:#333;">
  <div style="background:#1a3c5e;color:white;padding:20px 24px;border-radius:8px 8px 0 0;">
    <h1 style="margin:0;font-size:20px;">Afrika Haberleri</h1>
    <p style="margin:4px 0 0;opacity:0.8;font-size:14px;">Gunluk Pipeline Raporu - ${today}</p>
  </div>
  <div style="border:1px solid #ddd;border-top:none;padding:24px;border-radius:0 0 8px 8px;">
    ${noDataMsg}
    <table style="width:100%;border-collapse:collapse;font-size:14px;">
      <thead>
        <tr style="background:#f0f4f8;">
          <th style="padding:10px 12px;text-align:left;border-bottom:2px solid #ddd;">Kaynak</th>
          <th style="padding:10px 12px;text-align:center;border-bottom:2px solid #ddd;">Cekilen</th>
          <th style="padding:10px 12px;text-align:center;border-bottom:2px solid #ddd;">Kopya</th>
          <th style="padding:10px 12px;text-align:center;border-bottom:2px solid #ddd;">Dusuk Skor</th>
          <th style="padding:10px 12px;text-align:center;border-bottom:2px solid #ddd;">TR Filtresi</th>
          <th style="padding:10px 12px;text-align:center;border-bottom:2px solid #ddd;">Yayinlanan</th>
          <th style="padding:10px 12px;text-align:center;border-bottom:2px solid #ddd;">Ort. Skor</th>
        </tr>
      </thead>
      <tbody>${tableRows}</tbody>
    </table>
    <p style="margin-top:20px;font-size:12px;color:#999;">Bu rapor her sabah 08:00 TST'de otomatik olarak gonderilir.</p>
  </div>
</body></html>`;

return [{ json: { html, subject: 'Afrika Haberleri Pipeline Raporu (' + today + ')' } }];
